SELECT
id, user_id, api_id, subject, model,
user_answer, correct_answer, answer_time,
exam_record_id,
create_time
FROM error_question
WHERE user_id = #{userId}
AND subject = #{subject}
AND model = #{model}
ORDER BY answer_time DESC

SELECT COUNT(*)
FROM error_question
WHERE user_id = #{userId}
  AND subject = #{subject}
